import{_ as s,o as e,c as a,al as r}from"./chunks/framework.BcI6aB5X.js";const c=JSON.parse('{"title":"Single Page（SPA）","description":"","frontmatter":{"command":"new spa","function":"SPA 单页应用","order":3,"options":null},"headers":[],"relativePath":"rust/dioxus/start/new-spa.md","filePath":"rust/dioxus/start/new-spa.md","lastUpdated":0}'),o={name:"rust/dioxus/start/new-spa.md"};function d(i,t,n,l,h,g){return e(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="single-page-spa" tabindex="-1">Single Page（SPA） <a class="header-anchor" href="#single-page-spa" aria-label="Permalink to “Single Page（SPA）”">​</a></h1><p>适用于 <strong>仅浏览器内运行</strong> 的单页应用：无独立 Dioxus 服务端二进制，构建产物以 <strong>WASM + 静态资源</strong> 为主，部署到任意静态站点或 CDN 即可（后端 API 可仍由其它服务提供）。</p><h2 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to “步骤”">​</a></h2><ol><li>已安装 CLI 与 Rust（见 <a href="./install.html">安装</a>）。</li><li>执行：</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-spa</span></span></code></pre></div><ol start="3"><li><p>提示 <code>Which sub-template should be expanded?</code>，用方向键选择后回车：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><strong>Bare-Bones</strong></td><td>最少代码，近似最基础的 <code>main.rs</code> 和资源目录。适合跟教程从零开始，或只需极简 Demo 的场景。</td></tr><tr><td><strong>Jumpstart</strong></td><td>包含预设目录结构与脚手架（如组件、视图等常见拆分）。绝大多数 SPA 入门推荐选择，上手最快（✅ 推荐）</td></tr><tr><td><strong>Workspace</strong></td><td>基于 <strong>Cargo workspace</strong>，支持多 crate，适合中大型项目需求。建议已有 workspace 经验或明确需多包架构时选择</td></tr></tbody></table></li><li><p>提示 <strong><code>Do you want to use Dioxus Fullstack?</code></strong>：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><strong>false</strong></td><td>仅需浏览器内 SPA，暂不需要 Dioxus 内置后端（✅ 推荐）</td></tr><tr><td><strong>true</strong></td><td>若构建<strong>前后端同仓</strong>全栈应用，可选 true</td></tr></tbody></table><p>做纯 SPA 时选 <strong>false</strong>。默认开发目标（<strong>Web</strong>）在第 <strong>6</strong> 步里选择。</p></li><li><p>提示 <strong><code>Do you want to use Dioxus Router?</code></strong>：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><strong>false</strong></td><td>工程中<strong>不内置路由</strong>：整站只有一个根组件，适合极简 Demo，或你更倾向自行用状态切换 UI，不使用官方路由。</td></tr><tr><td><strong>true</strong></td><td>推荐选项：集成 <strong>dioxus-router</strong>，支持多页面、浏览器地址栏、<code>Route</code>/嵌套路由等典型 SPA 需求。（✅ 推荐）</td></tr></tbody></table><ul><li><strong>Tailwind</strong>、LLM 提示等其余选项按项目需要勾选（✅ 推荐 true）。</li></ul></li><li><p>提示 <strong><code>Which platform do you want DX to serve by default?</code></strong>：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><strong>Web</strong></td><td>默认用 <strong><code>dx serve</code> 针对 Web/WASM</strong> 启动开发，符合 SPA 部署路径。（✅ 推荐）</td></tr><tr><td><strong>Desktop</strong></td><td>默认面向桌面窗口；更适合 <a href="./new-desktop.html">Desktop</a>。</td></tr><tr><td><strong>Mobile</strong></td><td>默认面向移动端；更适合 <a href="./new-mobile.html">Mobile</a>。</td></tr></tbody></table><p>该选项决定 <strong><code>dx serve</code> 不带额外参数时的默认目标</strong>；仍可用 <code>dx serve --desktop</code> 等覆盖。</p></li><li><p>本地预览：</p></li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-spa</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>浏览器访问终端里给出的本地地址（常见为 <code>http://127.0.0.1:8080</code>，以实际输出为准）。</p><h2 id="与-fullstack-的区别" tabindex="-1">与 Fullstack 的区别 <a class="header-anchor" href="#与-fullstack-的区别" aria-label="Permalink to “与 Fullstack 的区别”">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>SPA（本页）</strong></td><td>通常采用静态托管方式进行部署，前端直接发布到 CDN 或静态文件服务器，如 Vercel、GitHub Pages、Netlify 等。后端若有需求，可以接入外部的 API 服务。</td></tr><tr><td><strong>Fullstack Web</strong></td><td>客户端与服务端集成在一个项目中，由 Dioxus 提供全栈能力。既包括运行于浏览器的前端 WASM 应用，也包含服务端（如 Axum）的后端逻辑。</td></tr></tbody></table><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to “参考”">​</a></h2><ul><li><a href="https://dioxuslabs.com/learn/0.7/tutorial/new_app/" target="_blank" rel="noreferrer">Tutorial — Creating a new project</a>（文中 “fullstack 选 false、平台选 Web” 的示例即偏 SPA 入门）</li></ul>`,12)])])}const b=s(o,[["render",d]]);export{c as __pageData,b as default};
